import{_ as i,o as s,c as a,a6 as t}from"./chunks/framework.DtxWasON.js";const u=JSON.parse('{"title":"Configuring Sentries (for Validators)","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/networks/sentry.md","filePath":"mainchain/networks/sentry.md"}'),o={name:"mainchain/networks/sentry.md"};function n(r,e,l,d,h,c){return s(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="configuring-sentries-for-validators" tabindex="-1">Configuring Sentries (for Validators) <a class="header-anchor" href="#configuring-sentries-for-validators" aria-label="Permalink to &quot;Configuring Sentries (for Validators)&quot;">​</a></h1><p>Although not essential, it is highly recommended to configure at least one (preferably two or more) sentries to protect a validator node. Conceptually, sentries act as a P2P &quot;firewall&quot; for a validator node, protecting it from DDoS and other attacks. The validator node runs in private subnet and communicates only with its configured sentries, which relay information to and from the public blockchain network.</p><div class="tip custom-block"><p class="custom-block-title">Note</p><p>The Validator should have egress access to the Internet via a configured NAT or Proxy to allow for software updates etc.</p></div><p>This guide will outline the steps and configurations required to set up a 2-Sentry network. It will use generic IP addresses and pseudo firewall rules for demonstration purposes only and should therefore not be copied verbatim to your own configuration. SSH configuration is out of scope for this guide, which will only deal with the required P2P ports. It is assumed the reader has configured their own SSH tunnel, Bastion etc. for access to their nodes.</p><h2 id="example-network" tabindex="-1">Example Network <a class="header-anchor" href="#example-network" aria-label="Permalink to &quot;Example Network&quot;">​</a></h2><p>Cloud platforms each have their own methods for configuring public and private subnets. Generally, hosts on a private subnet will not be assigned a public IP and will require Internet access via a NAT gateway or similar. Hosts on a public subnet will be assigned a public IP, and will have direct access to the Internet. If the subnets are created within the same VPN, then communication should be possible between hosts on the different subnets.</p><p>Configuring VPNs and subnets is out of scope for this guide</p><h3 id="validator" tabindex="-1">Validator <a class="header-anchor" href="#validator" aria-label="Permalink to &quot;Validator&quot;">​</a></h3><p>Private Subnet<br> Private IP: <code>10.0.0.3</code><br> Public IP: N/A</p><h3 id="sentry-1" tabindex="-1">Sentry 1 <a class="header-anchor" href="#sentry-1" aria-label="Permalink to &quot;Sentry 1&quot;">​</a></h3><p>Public Subnet<br> Private IP: <code>10.1.1.4 </code><br> Public IP: <code>123.123.22.33</code></p><h3 id="sentry-2" tabindex="-1">Sentry 2 <a class="header-anchor" href="#sentry-2" aria-label="Permalink to &quot;Sentry 2&quot;">​</a></h3><p>Public Subnet<br> Private IP: <code>10.1.1.5</code><br> Public IP: <code>234.234.33.44</code></p><h2 id="firewall-configuration" tabindex="-1">Firewall Configuration <a class="header-anchor" href="#firewall-configuration" aria-label="Permalink to &quot;Firewall Configuration&quot;">​</a></h2><p>There should be two firewall rules covering P2P access - one for private access between sentries and the Validator, and another of public P2P access. For example:</p><ol><li>Validator - allow ingress on port <code>26656</code> from <code>10.1.1.4/32</code> (Sentry 1) and <code>10.1.1.5/32</code> (Sentry 2)</li><li>Sentries - allow ingres access on port <code>26656</code> from <code>0.0.0.0/0</code> (everyone)</li></ol><h2 id="node-configuration" tabindex="-1">Node Configuration <a class="header-anchor" href="#node-configuration" aria-label="Permalink to &quot;Node Configuration&quot;">​</a></h2><p>The Sentry nodes should be installed, running, and fully synced. Once fully synced, it is possible to reconfigure the nodes to communicate directly with each other by editing the <code>.und_mainchain/config/config.toml</code> file.</p><p>All configuration parameters are in the <code>[p2p]</code> section of <code>config.toml</code></p><h3 id="validator-1" tabindex="-1">Validator <a class="header-anchor" href="#validator-1" aria-label="Permalink to &quot;Validator&quot;">​</a></h3><p>The Valildator&#39;s <code>config.toml</code> should contain somethign along the lines of:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">seeds = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pex = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">persistent_peers = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sentry_1_node_id@10.1.1.4:26656,sentry_2_node_id@10.1.1.5:26656&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">unconditional_peer_ids = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sentry_1_node_id,sentry_2_node_id&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addr_book_strict = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><ul><li><code>seeds</code> is not required to be set, because the validator should not communicate directly with other P2P nodes that are not its sentries, or broadcast its P2P address.</li><li><code>pex</code> is set to <code>false</code>, since the validator will not broadcast or consume the wider network&#39;s P2P data.</li><li><code>persistent_peers</code> is set to the two Sentry nodes&#39; P2P addresses.</li><li><code>unconditional_peer_ids</code> ensures that the validator will always try to connect to the sentry nodes.</li><li><code>addr_book_strict</code> allows the node address book to store private IP addresses, since <code>persistent_peers</code> is configured to use the private IPs of the sentry nodes.</li></ul><h3 id="sentry-1-1" tabindex="-1">Sentry 1 <a class="header-anchor" href="#sentry-1-1" aria-label="Permalink to &quot;Sentry 1&quot;">​</a></h3><p>Sentry 1 should be configured to connect to the Validator and to Sentry 2, for example:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">seeds = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0c2b65bc604a18a490f5f55bb7b4140cfb512ced@seed1.unification.io:26656,e66e0f89af19da09f676c85b262d591b8c2bb9d8@seed2.unification.io:26656&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pex = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">persistent_peers = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;validator_node_id@10.0.0.3:26656,sentry_2_node_id@234.234.33.44:26656,&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">unconditional_peer_ids = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;validator_node_id,sentry_2_node_id&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">private_peer_ids= </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;validator_node_id&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addr_book_strict = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><ul><li><code>seeds</code> is set as normal, so that the Sentry can query for more P2P addresses and broadcast its own</li><li><code>pex</code> is set to true to allow for P2P address propagation</li><li><code>persistent_peers</code> is set to the Validator (private IP), and optionally Sentry 2. Note that for Sentry 2 the public IP is used, otherwise the private IP version of the node address would be stored in its address book and broadcast.</li><li><code>unconditional_peer_ids</code> is set to the Validator&#39;s Node ID and optionally Sentry 2&#39;s Node ID</li><li><code>private_peer_ids</code> is set to the Validator&#39;s Node ID to ensure that its P2P address is never gossiped/broadcast to the network.</li><li><code>addr_book_strict</code> is set to false to allow the node to store the validator&#39;s private IP.</li></ul><h3 id="sentry-2-1" tabindex="-1">Sentry 2 <a class="header-anchor" href="#sentry-2-1" aria-label="Permalink to &quot;Sentry 2&quot;">​</a></h3><p>Sentry 2 should be configured to connect to the Validator and to Sentry 1, for example:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">seeds = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0c2b65bc604a18a490f5f55bb7b4140cfb512ced@seed1.unification.io:26656,e66e0f89af19da09f676c85b262d591b8c2bb9d8@seed2.unification.io:26656&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pex = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">persistent_peers = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;validator_node_id@10.0.0.3:26656,sentry_1_node_id@123.123.22.33:26656,&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">unconditional_peer_ids = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;validator_node_id,sentry_1_node_id&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">private_peer_ids= </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;validator_node_id&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">addr_book_strict = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>Notes are similar to those outlined for Sentry 1.</p>`,31)])])}const k=i(o,[["render",n]]);export{u as __pageData,k as default};
